module RefModule (
    input Clk,
    input Enable,
    input Reset,
    input [7:0] D,
    output reg [7:0] Q
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge Clk or posedge dbg_halt) begin
    if (Reset)
        Q <= 8'b00000000;
    else if (Enable)
        Q <= D;
end

endmodule
